SELECT 'profiles_approval_summary' AS audit_section, COUNT(*) AS total_profiles, COUNT(*) FILTER (WHERE deleted_at IS NULL) AS live_profiles, COUNT(*) FILTER (WHERE deleted_at IS NULL AND COALESCE(is_active, false) = true AND COALESCE(is_approved, false) = true) AS approved_active_profiles, COUNT(*) FILTER (WHERE deleted_at IS NULL AND COALESCE(is_approved, false) = false) AS not_approved_or_null_profiles, COUNT(*) FILTER (WHERE deleted_at IS NULL AND is_approved IS NULL) AS null_approval_profiles FROM public.profiles;
SELECT 'watch_tables_rls' AS audit_section, v.table_name, c.relrowsecurity AS rls_enabled, c.relforcerowsecurity AS rls_forced FROM (VALUES ('profiles'), ('products'), ('customers'), ('inventory_transactions'), ('inventory_opening_balances'), ('delivery_plans'), ('shipment_logs'), ('selling_entities'), ('vehicles'), ('system_settings'), ('inventory_stocktakes'), ('inventory_stocktake_lines'), ('inventory_report_closures'), ('inventory_report_closure_lines'), ('phoi_transactions'), ('returned_goods_records')) AS v(table_name) LEFT JOIN pg_class c ON c.relname = v.table_name AND c.relnamespace = 'public'::regnamespace ORDER BY v.table_name;
SELECT 'watch_policies' AS audit_section, p.tablename, p.policyname, p.cmd, p.roles, p.qual, p.with_check FROM pg_policies p WHERE p.schemaname = 'public' AND p.tablename IN ('profiles', 'products', 'customers', 'inventory_transactions', 'inventory_opening_balances', 'delivery_plans', 'shipment_logs', 'selling_entities', 'vehicles', 'system_settings', 'inventory_stocktakes', 'inventory_stocktake_lines', 'inventory_report_closures', 'inventory_report_closure_lines', 'phoi_transactions', 'returned_goods_records') ORDER BY p.tablename, p.policyname;
SELECT 'open_policy_candidates' AS audit_section, p.tablename, p.policyname, p.cmd, p.qual, p.with_check FROM pg_policies p WHERE p.schemaname = 'public' AND p.tablename IN ('products', 'customers', 'inventory_transactions', 'inventory_opening_balances', 'delivery_plans', 'shipment_logs', 'selling_entities', 'vehicles', 'system_settings', 'inventory_stocktakes', 'inventory_stocktake_lines', 'inventory_report_closures', 'inventory_report_closure_lines', 'phoi_transactions', 'returned_goods_records') AND (COALESCE(p.qual, '') = 'true' OR (p.cmd = 'SELECT' AND COALESCE(p.qual, '') NOT ILIKE '%is_approved_active_user%')) ORDER BY p.tablename, p.policyname;
SELECT 'watch_table_grants' AS audit_section, table_name, grantee, privilege_type FROM information_schema.role_table_grants WHERE table_schema = 'public' AND grantee IN ('anon', 'authenticated') AND table_name IN ('profiles', 'products', 'customers', 'inventory_transactions', 'inventory_opening_balances', 'delivery_plans', 'shipment_logs', 'selling_entities', 'vehicles', 'system_settings', 'inventory_stocktakes', 'inventory_stocktake_lines', 'inventory_report_closures', 'inventory_report_closure_lines', 'phoi_transactions', 'returned_goods_records') ORDER BY table_name, grantee, privilege_type;
SELECT 'watch_rpc_access' AS audit_section, p.proname AS function_name, pg_get_function_identity_arguments(p.oid) AS args, p.prosecdef AS security_definer, has_function_privilege('anon', p.oid, 'EXECUTE') AS anon_can_execute, has_function_privilege('authenticated', p.oid, 'EXECUTE') AS authenticated_can_execute FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = 'public' AND p.proname IN ('is_approved_active_user', 'require_approved_active_user', 'is_admin', 'is_manager', 'check_is_admin', 'can_edit_delivery_plan', 'inventory_calculate_product_stock_v1', 'inventory_calculate_product_stock_v1_unsafe_20260710', 'sales_command_center_report_v2', 'sales_command_center_report_v2_unsafe_20260710', 'inventory_get_last_tx_dates') ORDER BY p.proname, args;
